import Layout from "../components/layout"


class Projects extends React.Component {

    constructor(props) {
        super(props);
        this.state = {animate:false,selectedCategory:"all",projectsHide:false,isMobile:false}
      }  


      render(){

     
    return(


        <Layout page="about" navPosition="absolute" navTextColor="black" menuBtnColor="black" hindiText="white" footerType="yellow">
        <div>
            
  
            <div className="relative-items position-relative">
                <div className="fun futura-light overflow-hidden">
                    <div className="child">
                      WE TAKE FUN SERIOUSLY
                    </div>
                </div>
                <div className="top-title overflow-hidden">
                    <div className="child">
                      About us
                    </div>
                </div>
                <div className="bg-text helvetica-neue-condensed overflow-hidden">
                  <div className="child">
                    raison<br/>
                    d’être
                  </div>
                </div>
            </div>
        </div>

        </Layout>
    ) 
  }
}
function mapStateToProps({ common }) {
    return {
      common,
    };
  }
  export default connect(mapStateToProps, {openMenu,setMenuBtnColor})(Projects);
